function uninstallShRoute() {
  const script = `#!/usr/bin/env bash
set -e

BOLD="\\033[1m"
GREEN="\\033[0;32m"
DIM="\\033[2m"
NC="\\033[0m"

echo ""
echo -e "\${BOLD}Aiden Uninstaller\${NC}"
echo "──────────────────"

remove_if_exists() {
  if [ -d "$1" ] || [ -f "$1" ]; then
    rm -rf "$1"
    echo -e "  \${GREEN}removed\${NC}  $1"
  fi
}

echo ""
echo "Removing Aiden data and config..."
remove_if_exists "$HOME/.local/share/aiden"
remove_if_exists "$HOME/.config/aiden"

if [[ "$(uname)" == "Darwin" ]]; then
  remove_if_exists "$HOME/Library/Application Support/aiden"
  remove_if_exists "$HOME/Library/Preferences/com.taracod.aiden.plist"
fi

if command -v npm &>/dev/null; then
  npm uninstall -g devos-ai 2>/dev/null && echo -e "  \${GREEN}removed\${NC}  npm global: devos-ai" || true
fi

echo ""
echo -e "\${GREEN}\${BOLD}Done.\${NC} Aiden has been uninstalled."
echo "Thanks for trying Aiden — feedback welcome: discord.gg/gMZ3hUnQTm"
echo ""
`
  return new Response(script, {
    status: 200,
    headers: {
      'Content-Type': 'text/plain; charset=utf-8',
      'Cache-Control': 'no-cache',
    }
  })
}

function uninstallPs1Route() {
  // Serve the Windows uninstall script.
  // Usage: irm https://aiden.taracod.com/uninstall.ps1 | iex
  const script = `# Aiden Windows Uninstaller
# Usage:  irm https://aiden.taracod.com/uninstall.ps1 | iex
# Flags:  -KeepWorkspace  -KeepConfig  -Yes

param([switch]$KeepWorkspace,[switch]$KeepConfig,[switch]$Yes)
$ErrorActionPreference="SilentlyContinue"
$E=[char]27;$B="$E[1m";$G="$E[32m";$D="$E[2m";$R="$E[0m"

Write-Host ""
Write-Host ($B+"Aiden - Uninstaller"+$R)
Write-Host ($D+"------------------------------------"+$R)
Write-Host ""

$removed=0

function Rm($p,$l){
  if(Test-Path $p){
    Remove-Item -Recurse -Force $p -EA SilentlyContinue
    Write-Host ("  "+$G+"removed"+$R+"  "+$l)
    $script:removed++
  }else{
    Write-Host ("  "+$D+"skipped"+$R+"  "+$l+" "+$D+"(not found)"+$R)
  }
}

Write-Host "Stopping Aiden server (port 4200)..."
$proc=Get-NetTCPConnection -LocalPort 4200 -State Listen -EA SilentlyContinue|
  Select-Object -First 1 -Expand OwningProcess
if($proc){
  Stop-Process -Id $proc -Force -EA SilentlyContinue
  Write-Host ("  "+$G+"stopped"+$R+"  pid $proc")
}else{
  Write-Host ("  "+$D+"skipped"+$R+"  no process on :4200")
}
Write-Host ""

if(-not $KeepConfig){
  $appData=if($env:APPDATA){$env:APPDATA}else{Join-Path $env:USERPROFILE "AppData\\Roaming"}
  $local=if($env:LOCALAPPDATA){$env:LOCALAPPDATA}else{Join-Path $env:USERPROFILE "AppData\\Local"}
  Write-Host "Removing Aiden user data..."
  Rm (Join-Path $appData "aiden") "%APPDATA%\\aiden"
  Rm (Join-Path $local "aiden") "%LOCALAPPDATA%\\aiden"
  Write-Host ""
}

if(-not $KeepWorkspace){
  $ws=Join-Path $env:USERPROFILE ".aiden-workspace"
  if(Test-Path $ws){
    if(-not $Yes){$a=Read-Host "  Delete workspace? [y/N]"}else{$a="y"}
    if($a -match "^[Yy]"){Rm $ws "~/.aiden-workspace"}
    else{Write-Host ("  "+$D+"kept"+$R+"  workspace")}
    Write-Host ""
  }
}

Write-Host "Checking for npm global install..."
$nl=npm list -g --depth=0 2>$null
if($nl -match "devos-ai|aiden-os|aiden-runtime"){
  $pkg=if($nl -match "aiden-os"){"aiden-os"}
       elseif($nl -match "devos-ai"){"devos-ai"}
       else{"aiden-runtime"}
  npm uninstall -g $pkg 2>$null
  Write-Host ("  "+$G+"removed"+$R+"  npm global: $pkg")
  $removed++
}else{
  Write-Host ("  "+$D+"skipped"+$R+"  no npm global package found")
}
Write-Host ""

if($removed -gt 0){
  Write-Host ($G+$B+"Done."+$R+" Aiden uninstalled ($removed item(s) removed).")
}else{
  Write-Host ($D+"Nothing to remove."+$R)
}
Write-Host ""`
  return new Response(script, {
    status: 200,
    headers: {
      'Content-Type': 'text/plain; charset=utf-8',
      'Cache-Control': 'no-cache',
      'Content-Disposition': 'inline; filename=uninstall.ps1',
    }
  })
}

function installShRoute() {
  // Proxy install.sh from the source repo raw URL.
  const RAW_URL = 'https://raw.githubusercontent.com/taracodlabs/aiden-releases/main/install.sh'
  return fetch(RAW_URL).then(res => {
    if (!res.ok) {
      return new Response('#!/usr/bin/env bash\necho "install.sh temporarily unavailable"\nexit 1\n', {
        status: 503,
        headers: { 'Content-Type': 'text/plain;charset=UTF-8' }
      })
    }
    return res.text().then(body => new Response(body, {
      status: 200,
      headers: {
        'Content-Type': 'text/plain;charset=UTF-8',
        'Cache-Control': 'public, max-age=300'
      }
    }))
  })
}

function installPs1Route() {
  // Proxy the install.ps1 from the source repo raw URL.
  // Cache for 5 minutes so updates propagate quickly.
  const RAW_URL = 'https://raw.githubusercontent.com/taracodlabs/aiden-releases/main/install.ps1'
  return fetch(RAW_URL).then(res => {
    if (!res.ok) {
      return new Response('# install.ps1 temporarily unavailable\n', {
        status: 503,
        headers: { 'Content-Type': 'text/plain;charset=UTF-8' }
      })
    }
    return res.text().then(body => new Response(body, {
      status: 200,
      headers: {
        'Content-Type': 'text/plain;charset=UTF-8',
        'Cache-Control': 'public, max-age=300'
      }
    }))
  })
}

